sparql:
PREFIX vg: <http://videogamekg.org/ontology#>
PREFIX ent: <http://videogamekg.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?label WHERE {
    ?g a vg:Game ;
       vg:developedBy ent:Bohemia_Interactive ;
       rdfs:label ?label .
    FILTER(lang(?label)="en")
}

PREFIX vg: <http://videogamekg.org/ontology#>
PREFIX ent: <http://videogamekg.org/entity/>
SELECT ?genre WHERE {
    ent:Armello vg:hasGenre ?genre .
}

PREFIX vg: <http://videogamekg.org/ontology#>
PREFIX ent: <http://videogamekg.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?label WHERE {
    ?g a vg:Game ;
       vg:availableOn ent:PC ;
       vg:hasGenre ent:RPG ;
       rdfs:label ?label .
    FILTER(lang(?label)="en")
} LIMIT 10

PREFIX vg: <http://videogamekg.org/ontology#>
PREFIX ent: <http://videogamekg.org/entity/>
SELECT ?score WHERE {
    ent:Assassin_s_Creed_Valhalla vg:metacritic ?score .
}

PREFIX vg: <http://videogamekg.org/ontology#>
PREFIX ent: <http://videogamekg.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?label WHERE {
    ?g1 a vg:Game ;
        vg:hasGenre ent:Action .
    ?g2 a vg:Game ;
        vg:hasGenre ent:RPG ;
        vg:sameStudioAs ?g1 .
    ?g1 rdfs:label ?label .
}

PREFIX vg: <http://videogamekg.org/ontology#>
PREFIX ent: <http://videogamekg.org/entity/>
SELECT ?label WHERE {
    ?g a vg:Game ;
       rdfs:label ?label ;
       vg:availableOn ?p .
    ?p a vg:Platform ;
       rdfs:label ?platformLabel .
    FILTER(lang(?label)="en")
    FILTER(lang(?platformLabel)="en")
}

PREFIX vg:   <http://videogamekg.org/ontology#>
PREFIX ent:  <http://videogamekg.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?label WHERE {
    ?g a vg:Game ;
       vg:publishedBy ent:Devolver_Digital ;
       rdfs:label ?label .
    FILTER(lang(?label)="en")
} LIMIT 10
